// build-image-grounding — Validate Inputs
// Extracts products with their Shopify image URLs.

const input = $input.first().json;
const projectId = input.project_id || null;
const products  = input.products || (input.store_blueprint && input.store_blueprint.products) || [];
const shopifyImport = input.shopify_import || null;
const runtimeConfig = input.runtime_config || {};

if (!projectId) throw new Error('MISSING_INPUT: build-image-grounding requires project_id');
if (products.length === 0) throw new Error('MISSING_INPUT: no products provided');

// Merge Shopify import image data onto products
const rawProducts = (shopifyImport && shopifyImport.raw_products) || [];
const rawByHandle = {};
for (const rp of rawProducts) {
  if (rp.handle) rawByHandle[rp.handle] = rp;
}

const enrichedProducts = products.map(p => {
  const raw = rawByHandle[p.handle] || {};
  const images = raw.images || p.images || [];
  return {
    handle: p.handle,
    title: p.title || raw.title || p.handle,
    images: images.map(img => ({
      url: img.src || img.url || img,
      alt: img.alt || null,
      id: img.id || null,
    })).filter(img => img.url),
  };
});

const productsWithImages = enrichedProducts.filter(p => p.images.length > 0);
const productsWithout    = enrichedProducts.filter(p => p.images.length === 0);

const groundingModel = runtimeConfig.grounding_model || 'gemini-2.0-flash';

console.log('build-image-grounding: ' + productsWithImages.length + ' products with images, ' + productsWithout.length + ' without');

return [{
  json: {
    project_id: projectId,
    grounding_model: groundingModel,
    products_with_images: productsWithImages,
    products_without_images: productsWithout.map(p => p.handle),
    total_images: productsWithImages.reduce((sum, p) => sum + p.images.length, 0),
  },
}];

// build-image-grounding — Prepare Vision Requests
// Downloads each product's primary image, converts to base64,
// and builds Gemini Vision API payloads.

const input = $input.first().json;
const products = input.products_with_images;
const model = input.grounding_model;

const ANALYSIS_PROMPT = `You are a product image analyst for an ecommerce platform. Analyze this product image and return a JSON object with EXACTLY this structure (no markdown, no code fences, just raw JSON):

{
  "category": "<product category>",
  "form_factor": "<physical shape/silhouette description>",
  "materials": ["<material1>", "<material2>"],
  "primary_colors": ["<hex1>", "<hex2>"],
  "color_description": "<human-readable color summary>",
  "distinctive_features": ["<feature1>", "<feature2>"],
  "dimensions_estimate": "<relative size estimate>",
  "orientation": "<primary product orientation>",
  "surface_finish": "<matte/glossy/brushed/textured/etc>",
  "brand_markings": "<visible brand text or null>",
  "background_quality": "<assessment of background>",
  "lighting_quality": "<assessment of lighting>",
  "ecommerce_suitability": "<high/medium/low>",
  "improvement_suggestions": ["<suggestion1>"],
  "product_description_grounded": "<detailed physical description for image generation prompts — be specific about shape, material, color, texture, distinctive features>",
  "material_keywords": "<comma-separated material terms>",
  "shape_keywords": "<comma-separated shape/form terms>",
  "detail_focus_areas": ["<area1>", "<area2>"],
  "quality_score": <0.0-1.0>,
  "usable_as": ["<product_image/hero_banner/collection_image/lifestyle/detail_shot>"],
  "reuse_recommendation": "<keep/enhance/replace>",
  "issues": ["<issue1 or empty>"]
}

Be precise about physical product characteristics. Focus on what makes this product visually unique and recognizable. The grounded description will be used to generate faithful product photography.`;

const items = [];

for (const product of products) {
  // Use first image, resize via Shopify CDN for efficiency
  const primaryImg = product.images[0];
  let imgUrl = primaryImg.url;
  // Shopify CDN resize: append width parameter
  if (imgUrl.includes('cdn.shopify.com')) {
    const sep = imgUrl.includes('?') ? '&' : '?';
    imgUrl = imgUrl + sep + 'width=800';
  }

  // Download image and convert to base64
  let base64Data = null;
  let mimeType = 'image/jpeg';
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: imgUrl,
      encoding: 'arraybuffer',
      returnFullResponse: true,
    });
    const buffer = Buffer.from(response.body);
    base64Data = buffer.toString('base64');
    mimeType = response.headers['content-type'] || 'image/jpeg';
    if (mimeType.includes(';')) mimeType = mimeType.split(';')[0].trim();
  } catch (err) {
    console.log('Failed to download image for ' + product.handle + ': ' + err.message);
  }

  if (!base64Data) {
    items.push({
      json: {
        product_handle: product.handle,
        product_title: product.title,
        primary_image_url: primaryImg.url,
        all_images: product.images,
        _skip: true,
        _error: 'Failed to download image',
        _project_id: input.project_id,
        _model: model,
      },
    });
    continue;
  }

  // Build Gemini request body
  const geminiBody = {
    contents: [{
      parts: [
        { text: ANALYSIS_PROMPT },
        {
          inlineData: {
            mimeType: mimeType,
            data: base64Data,
          },
        },
      ],
    }],
    generationConfig: {
      temperature: 0.1,
      maxOutputTokens: 2048,
      responseMimeType: 'application/json',
    },
  };

  items.push({
    json: {
      product_handle: product.handle,
      product_title: product.title,
      primary_image_url: primaryImg.url,
      all_images: product.images,
      gemini_request_body: geminiBody,
      _skip: false,
      _project_id: input.project_id,
      _model: model,
    },
  });
}

return items;

// build-image-grounding — Compile Grounding Artifact
// Parses Gemini Vision responses and assembles the final grounding artifact.

const allItems = $input.all();
const prepItems = $('Prepare Vision Requests').all();

const products = [];
const errors = [];
let totalImagesAnalyzed = 0;
let projectId = null;
let groundingModel = null;

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i].json;
  // Find matching prep item
  const prep = prepItems[i]?.json || {};
  const handle = prep.product_handle || item.product_handle || 'unknown';
  const title = prep.product_title || item.product_title || handle;
  const primaryUrl = prep.primary_image_url || item.primary_image_url || null;
  const allImages = prep.all_images || [];
  projectId = projectId || prep._project_id;
  groundingModel = groundingModel || prep._model;

  // Check if this was a skipped item (no image)
  if (prep._skip) {
    products.push({
      product_handle: handle,
      product_title: title,
      primary_image_url: null,
      source_images_analyzed: 0,
      visual_analysis: {
        category: 'unknown',
        form_factor: 'unknown',
        materials: [],
        primary_colors: [],
        color_description: 'no image available',
        distinctive_features: [],
        dimensions_estimate: null,
        orientation: null,
        surface_finish: 'unknown',
        brand_markings: null,
        background_quality: 'n/a',
        lighting_quality: 'n/a',
        ecommerce_suitability: 'low',
        improvement_suggestions: ['No source images available — product images needed'],
      },
      grounding_prompt_additions: {
        product_description_grounded: title,
        material_keywords: '',
        shape_keywords: '',
        detail_focus_areas: [],
      },
      source_image_assessment: [],
      analysis_error: prep._error || 'No image available',
    });
    errors.push({ product_handle: handle, error_type: 'no_image', message: prep._error || 'No source image' });
    continue;
  }

  // Parse Gemini response
  const resp = item;
  const statusCode = resp.statusCode || 0;
  const body = resp.body || resp;

  let analysis = null;
  let parseError = null;

  if (statusCode >= 200 && statusCode < 300) {
    try {
      // Gemini response: body.candidates[0].content.parts[0].text
      const candidates = body.candidates || [];
      const textPart = candidates[0]?.content?.parts?.[0]?.text || '';
      // Parse JSON from response
      let cleaned = textPart.trim();
      // Strip markdown code fences if present
      if (cleaned.startsWith('```')) {
        cleaned = cleaned.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
      }
      analysis = JSON.parse(cleaned);
      totalImagesAnalyzed++;
    } catch (e) {
      parseError = 'Failed to parse Gemini response: ' + e.message;
    }
  } else {
    const errMsg = body?.error?.message || JSON.stringify(body).slice(0, 200);
    parseError = 'Gemini API error (HTTP ' + statusCode + '): ' + errMsg;
  }

  if (!analysis) {
    products.push({
      product_handle: handle,
      product_title: title,
      primary_image_url: primaryUrl,
      source_images_analyzed: 0,
      visual_analysis: {
        category: 'unknown', form_factor: 'unknown', materials: [], primary_colors: [],
        color_description: 'analysis failed', distinctive_features: [],
        surface_finish: 'unknown', ecommerce_suitability: 'low',
        improvement_suggestions: ['Visual analysis failed — retry needed'],
      },
      grounding_prompt_additions: {
        product_description_grounded: title,
        material_keywords: '', shape_keywords: '', detail_focus_areas: [],
      },
      source_image_assessment: [],
      analysis_error: parseError,
    });
    errors.push({ product_handle: handle, error_type: 'analysis_failed', message: parseError });
    continue;
  }

  // Build structured product grounding from Gemini analysis
  products.push({
    product_handle: handle,
    product_title: title,
    primary_image_url: primaryUrl,
    source_images_analyzed: 1,
    visual_analysis: {
      category: analysis.category || 'unknown',
      form_factor: analysis.form_factor || 'unknown',
      materials: analysis.materials || [],
      primary_colors: analysis.primary_colors || [],
      color_description: analysis.color_description || '',
      distinctive_features: analysis.distinctive_features || [],
      dimensions_estimate: analysis.dimensions_estimate || null,
      orientation: analysis.orientation || null,
      surface_finish: analysis.surface_finish || 'unknown',
      brand_markings: analysis.brand_markings || null,
      background_quality: analysis.background_quality || 'unknown',
      lighting_quality: analysis.lighting_quality || 'unknown',
      ecommerce_suitability: ['high', 'medium', 'low'].includes(analysis.ecommerce_suitability) ? analysis.ecommerce_suitability : 'medium',
      improvement_suggestions: analysis.improvement_suggestions || [],
    },
    grounding_prompt_additions: {
      product_description_grounded: analysis.product_description_grounded || title,
      material_keywords: analysis.material_keywords || '',
      shape_keywords: analysis.shape_keywords || '',
      detail_focus_areas: analysis.detail_focus_areas || [],
    },
    source_image_assessment: [{
      image_url: primaryUrl,
      quality_score: typeof analysis.quality_score === 'number' ? Math.min(1, Math.max(0, analysis.quality_score)) : 0.5,
      usable_as: analysis.usable_as || ['product_image'],
      issues: analysis.issues || [],
      reuse_recommendation: ['keep', 'enhance', 'replace'].includes(analysis.reuse_recommendation) ? analysis.reuse_recommendation : 'enhance',
    }],
    analysis_error: null,
  });
}

const successCount = products.filter(p => !p.analysis_error).length;
let status;
if (successCount === products.length && products.length > 0) {
  status = 'PHASE_12_COMPLETE';
} else if (successCount > 0) {
  status = 'PHASE_12_PARTIAL';
} else {
  status = 'PHASE_12_FAILED';
}

return [{
  json: {
    status,
    project_id: projectId,
    completed_at: new Date().toISOString(),
    products_analyzed: successCount,
    total_images_analyzed: totalImagesAnalyzed,
    grounding_model: groundingModel || 'gemini-2.0-flash',
    products,
    errors,
  },
}];
